// lib/logging/log_entry.dart
class LogEntry {
  final DateTime timestamp;
  final LogLevel level;
  final String category;
  final String message;
  final Map<String, dynamic>? metadata;
  final String? stackTrace;

  LogEntry({
    required this.level,
    required this.category,
    required this.message,
    this.metadata,
    this.stackTrace,
  }) : timestamp = DateTime.now();

  Map<String, dynamic> toJson() => {
        'timestamp': timestamp.toIso8601String(),
        'level': level.name,
        'category': category,
        'message': message,
        if (metadata != null) 'metadata': metadata,
        if (stackTrace != null) 'stackTrace': stackTrace,
      };

  @override
  String toString() =>
      '[${timestamp.toIso8601String()}] ${level.name.toUpperCase()} [$category] $message';
}

// lib/logging/sensitive_data_redactor.dart
class SensitiveDataRedactor {
  static const _sensitiveKeys = {
    'password',
    'passwd',
    'secret',
    'token',
    'access_token',
    'refresh_token',
    'id_token',
    'api_key',
    'apikey',
    'authorization',
    'auth',
    'credential',
    'credentials',
    'credit_card',
    'card_number',
    'cvv',
    'ssn',
    'social_security',
    'pin',
    'otp',
    'mfa_code',
    'totp',
    'private_key',
    'session_id',
    'cookie',
    'set-cookie',
    'x-api-key',
    'x-auth-token',
  };

  static const _redactedValue = '[REDACTED]';

  static const _sensitiveHeaderKeys = {
    'authorization',
    'cookie',
    'set-cookie',
    'x-api-key',
    'x-auth-token',
    'proxy-authorization',
  };

  /// Redact sensitive fields from a map recursively
  static Map<String, dynamic> redactMap(Map<String, dynamic>? input) {
    if (input == null) return {};
    final result = <String, dynamic>{};
    for (final entry in input.entries) {
      final keyLower = entry.key.toLowerCase();
      if (_sensitiveKeys.contains(keyLower)) {
        result[entry.key] = _redactedValue;
      } else if (entry.value is Map<String, dynamic>) {
        result[entry.key] = redactMap(entry.value as Map<String, dynamic>);
      } else if (entry.value is List) {
        result[entry.key] = _redactList(entry.value as List);
      } else {
        result[entry.key] = entry.value;
      }
    }
    return result;
  }

  static List _redactList(List input) {
    return input.map((item) {
      if (item is Map<String, dynamic>) {
        return redactMap(item);
      } else if (item is List) {
        return _redactList(item);
      }
      return item;
    }).toList();
  }

  /// Redact sensitive headers
  static Map<String, String> redactHeaders(Map<String, String>? headers) {
    if (headers == null) return {};
    final result = <String, String>{};
    for (final entry in headers.entries) {
      if (_sensitiveHeaderKeys.contains(entry.key.toLowerCase())) {
        // Show only the type (e.g., "Bearer") but redact the actual token
        if (entry.key.toLowerCase() == 'authorization') {
          final parts = entry.value.split(' ');
          if (parts.length > 1) {
            result[entry.key] = '${parts[0]} $_redactedValue';
          } else {
            result[entry.key] = _redactedValue;
          }
        } else {
          result[entry.key] = _redactedValue;
        }
      } else {
        result[entry.key] = entry.value;
      }
    }
    return result;
  }

  /// Redact email addresses partially
  static String redactEmail(String email) {
    final parts = email.split('@');
    if (parts.length != 2) return _redactedValue;
    final name = parts[0];
    final domain = parts[1];
    if (name.length <= 2) return '**@$domain';
    return '${name[0]}${'*' * (name.length - 2)}${name[name.length - 1]}@$domain';
  }

  /// Redact a string value, showing only first and last 2 chars
  static String redactString(String value, {int visibleChars = 2}) {
    if (value.length <= visibleChars * 2) return _redactedValue;
    return '${value.substring(0, visibleChars)}...$_redactedValue...${value.substring(value.length - visibleChars)}';
  }
}

// lib/logging/log_sink.dart
abstract class LogSink {
  Future<void> write(LogEntry entry);
  Future<void> flush();
  Future<void> dispose();
}

// lib/logging/console_log_sink.dart
import 'dart:developer' as developer;
import 'package:flutter/foundation.dart';

class ConsoleLogSink extends LogSink {
  final LogLevel minimumLevel;

  ConsoleLogSink({this.minimumLevel = LogLevel.debug});

  @override
  Future<void> write(LogEntry entry) async {
    if (entry.level.index < minimumLevel.index) return;

    final message = entry.toString();

    if (kDebugMode) {
      // In debug mode, use developer.log for better DevTools integration
      developer.log(
        message,
        name: entry.category,
        level: _mapLevel(entry.level),
        error: entry.level.index >= LogLevel.error.index ? entry.message : null,
        stackTrace: entry.stackTrace != null
            ? StackTrace.fromString(entry.stackTrace!)
            : null,
      );
    } else {
      // In release/profile mode, use debugPrint for throttled output
      debugPrint(message);
    }
  }

  int _mapLevel(LogLevel level) {
    switch (level) {
      case LogLevel.verbose:
        return 0;
      case LogLevel.debug:
        return 500;
      case LogLevel.info:
        return 800;
      case LogLevel.warning:
        return 900;
      case LogLevel.error:
        return 1000;
      case LogLevel.fatal:
        return 1200;
      case LogLevel.none:
        return 2000;
    }
  }

  @override
  Future<void> flush() async {}

  @override
  Future<void> dispose() async {}
}

// lib/logging/file_log_sink.dart
import 'dart:collection';
import 'dart:convert';
import 'dart:io';
import 'package:path_provider/path_provider.dart';

class FileLogSink extends LogSink {
  final LogLevel minimumLevel;
  final int maxFileSizeBytes;
  final int maxFiles;
  final Queue<LogEntry> _buffer = Queue();
  final int _bufferSize;
  File? _currentFile;
  bool _isWriting = false;

  FileLogSink({
    this.minimumLevel = LogLevel.info,
    this.maxFileSizeBytes = 5 * 1024 * 1024, // 5MB
    this.maxFiles = 5,
    int bufferSize = 50,
  }) : _bufferSize = bufferSize;

  Future<File> _getLogFile() async {
    if (_currentFile != null) return _currentFile!;
    final dir = await getApplicationDocumentsDirectory();
    final logDir = Directory('${dir.path}/logs');
    if (!await logDir.exists()) {
      await logDir.create(recursive: true);
    }
    _currentFile = File('${logDir.path}/app_log_current.jsonl');
    return _currentFile!;
  }

  @override
  Future<void> write(LogEntry entry) async {
    if (entry.level.index < minimumLevel.index) return;
    _buffer.add(entry);
    if (_buffer.length >= _bufferSize) {
      await flush();
    }
  }

  @override
  Future<void> flush() async {
    if (_isWriting || _buffer.isEmpty) return;
    _isWriting = true;

    try {
      final file = await _getLogFile();
      final entries = <LogEntry>[];
      while (_buffer.isNotEmpty) {
        entries.add(_buffer.removeFirst());
      }

      final lines =
          entries.map((e) => jsonEncode(e.toJson())).join('\n') + '\n';
      await file.writeAsString(lines, mode: FileMode.append);

      // Rotate if needed
      final stat = await file.stat();
      if (stat.size > maxFileSizeBytes) {
        await _rotateFiles();
      }
    } catch (e) {
      debugPrint('FileLogSink error: $e');
    } finally {
      _isWriting = false;
    }
  }

  Future<void> _rotateFiles() async {
    final dir = await getApplicationDocumentsDirectory();
    final logDir = Directory('${dir.path}/logs');

    // Delete oldest if at max
    for (int i = maxFiles - 1; i >= 1; i--) {
      final older = File('${logDir.path}/app_log_$i.jsonl');
      final newer = i == 1
          ? File('${logDir.path}/app_log_current.jsonl')
          : File('${logDir.path}/app_log_${i - 1}.jsonl');
      if (await newer.exists()) {
        if (i == maxFiles - 1 && await older.exists()) {
          await older.delete();
        }
        await newer.rename(older.path);
      }
    }

    _currentFile = File('${logDir.path}/app_log_current.jsonl');
  }

  @override
  Future<void> dispose() async {
    await flush();
  }
}

// lib/logging/remote_log_sink.dart
import 'dart:async';
import 'dart:collection';
import 'dart:convert';
import 'package:http/http.dart' as http;

class RemoteLogSink extends LogSink {
  final String endpoint;
  final LogLevel minimumLevel;
  final int batchSize;
  final Duration flushInterval;
  final Queue<LogEntry> _buffer = Queue();
  Timer? _flushTimer;
  bool _isDisposed = false;

  RemoteLogSink({
    required this.endpoint,
    this.minimumLevel = LogLevel.warning,
    this.batchSize = 20,
    this.flushInterval = const Duration(seconds: 30),
  }) {
    _flushTimer = Timer.periodic(flushInterval, (_) => flush());
  }

  @override
  Future<void> write(LogEntry entry) async {
    if (_isDisposed) return;
    if (entry.level.index < minimumLevel.index) return;
    _buffer.add(entry);
    if (_buffer.length >= batchSize) {
      await flush();
    }
  }

  @override
  Future<void> flush() async {
    if (_buffer.isEmpty) return;

    final entries = <LogEntry>[];
    while (_buffer.isNotEmpty && entries.length < batchSize) {
      entries.add(_buffer.removeFirst());
    }

    try {
      await http.post(
        Uri.parse(endpoint),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode({
          'logs': entries.map((e) => e.toJson()).toList(),
        }),
      );
    } catch (e) {
      // Re-add to buffer on failure (at the front)
      for (final entry in entries.reversed) {
        _buffer.addFirst(entry);
      }
      // Cap buffer to prevent memory issues
      while (_buffer.length > 1000) {
        _buffer.removeFirst();
      }
    }
  }

  @override
  Future<void> dispose() async {
    _isDisposed = true;
    _flushTimer?.cancel();
    await flush();
  }
}

// lib/logging/app_logger.dart
import 'package:flutter/foundation.dart';

class AppLogger {
  static AppLogger? _instance;
  final List<LogSink> _sinks = [];
  LogLevel _minimumLevel;
  final Map<String, dynamic> _globalContext = {};

  AppLogger._({LogLevel minimumLevel = LogLevel.verbose})
      : _minimumLevel = minimumLevel;

  static AppLogger get instance {
    _instance ??= AppLogger._();
    return _instance!;
  }

  static void initialize({
    required List<LogSink> sinks,
    LogLevel minimumLevel = LogLevel.verbose,
    Map<String, dynamic>? globalContext,
  }) {
    _instance = AppLogger._(minimumLevel: minimumLevel);
    _instance!._sinks.addAll(sinks);
    if (globalContext != null) {
      _instance!._globalContext.addAll(globalContext);
    }
  }

  void setGlobalContext(String key, dynamic value) {
    _globalContext[key] = value;
  }

  void setMinimumLevel(LogLevel level) {
    _minimumLevel = level;
  }

  void _log(
    LogLevel level,
    String category,
    String message, {
    Map<String, dynamic>? metadata,
    StackTrace? stackTrace,
  }) {
    if (level.index < _minimumLevel.index) return;

    final enrichedMetadata = <String, dynamic>{
      ..._globalContext,
      if (metadata != null) ...metadata,
    };

    final entry = LogEntry(
      level: level,
      category: category,
      message: message,
      metadata: enrichedMetadata.isNotEmpty ? enrichedMetadata : null,
      stackTrace: stackTrace?.toString(),
    );

    for (final sink in _sinks) {
      sink.write(entry);
    }
  }

  void verbose(String category, String message,
          {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.verbose, category, message, metadata: metadata);

  void debug(String category, String message,
          {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.debug, category, message, metadata: metadata);

  void info(String category, String message,
          {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.info, category, message, metadata: metadata);

  void warning(String category, String message,
          {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.warning, category, message, metadata: metadata);

  void error(String category, String message,
          {Map<String, dynamic>? metadata, StackTrace? stackTrace}) =>
      _log(LogLevel.error, category, message,
          metadata: metadata, stackTrace: stackTrace);

  void fatal(String category, String message,
          {Map<String, dynamic>? metadata, StackTrace? stackTrace}) =>
      _log(LogLevel.fatal, category, message,
          metadata: metadata, stackTrace: stackTrace);

  Future<void> flush() async {
    for (final sink in _sinks) {
      await sink.flush();
    }
  }

  Future<void> dispose() async {
    for (final sink in _sinks) {
      await sink.dispose();
    }
    _sinks.clear();
  }
}

// lib/logging/http_logging_interceptor.dart
import 'package:http/http.dart' as http;

class LoggingHttpClient extends http.BaseClient {
  final http.Client _inner;
  final AppLogger _logger;
  static const _category = 'HTTP';

  LoggingHttpClient({
    http.Client? inner,
    AppLogger? logger,
  })  : _inner = inner ?? http.Client(),
        _logger = logger ?? AppLogger.instance;

  @override
  Future<http.StreamedResponse> send(http.BaseRequest request) async {
    final stopwatch = Stopwatch()..start();
    final requestId =
        DateTime.now().microsecondsSinceEpoch.toRadixString(36);

    // Log request with REDACTED sensitive headers
    _logger.info(_category, 'Request: ${request.method} ${request.url}', metadata: {
      'requestId': requestId,
      'method': request.method,
      'url': request.url.toString(),
      'headers': SensitiveDataRedactor.redactHeaders(
        request.headers.map((k, v) => MapEntry(k, v)),
      ),
      // Log content length but NOT the body (may contain sensitive data)
      'contentLength': request.contentLength,
    });

    try {
      final response = await _inner.send(request);
      stopwatch.stop();

      final level = response.statusCode >= 400
          ? (response.statusCode >= 500 ? LogLevel.error : LogLevel.warning)
          : LogLevel.info;

      _logger._log(
        level,
        _category,
        'Response: ${response.statusCode} ${request.method} ${request.url}',
        metadata: {
          'requestId': requestId,
          'statusCode': response.statusCode,
          'durationMs': stopwatch.elapsedMilliseconds,
          'headers': SensitiveDataRedactor.redactHeaders(
            response.headers.map((k, v) => MapEntry(k, v)),
          ),
          'contentLength': response.contentLength,
        },
      );

      return response;
    } catch (e, stackTrace) {
      stopwatch.stop();
      _logger.error(
        _category,
        'Request failed: ${request.method} ${request.url} - $e',
        metadata: {
          'requestId': requestId,
          'durationMs': stopwatch.elapsedMilliseconds,
          'error': e.toString(),
        },
        stackTrace: stackTrace,
      );
      rethrow;
    }
  }
}

// lib/logging/database_logger.dart
class DatabaseLogger {
  static const _category = 'DATABASE';
  final AppLogger _logger;

  DatabaseLogger({AppLogger? logger}) : _logger = logger ?? AppLogger.instance;

  void logQuery({
    required String operation,
    required String table,
    int? rowsAffected,
    Duration? duration,
    Map<String, dynamic>? parameters,
  }) {
    // Redact any sensitive parameters
    final safeParams =
        parameters != null ? SensitiveDataRedactor.redactMap(parameters) : null;

    _logger.info(_category, '$operation on $table', metadata: {
      'operation': operation,
      'table': table,
      if (rowsAffected != null) 'rowsAffected': rowsAffected,
      if (duration != null) 'durationMs': duration.inMilliseconds,
      if (safeParams != null) 'parameters': safeParams,
    });
  }

  void logError({
    required String operation,
    required String table,
    required dynamic error,
    StackTrace? stackTrace,
  }) {
    _logger.error(
      _category,
      'Database error: $operation on $table - $error',
      metadata: {
        'operation': operation,
        'table': table,
        'error': error.toString(),
      },
      stackTrace: stackTrace,
    );
  }

  void logMigration({
    required int fromVersion,
    required int toVersion,
    required bool success,
    Duration? duration,
  }) {
    final level = success ? LogLevel.info : LogLevel.error;
    _logger._log(
      level,
      _category,
      'Migration ${success ? "completed" : "failed"}: v$fromVersion -> v$toVersion',
      metadata: {
        'fromVersion': fromVersion,
        'toVersion': toVersion,
        'success': success,
        if (duration != null) 'durationMs': duration.inMilliseconds,
      },
    );
  }
}

// lib/logging/auth_logger.dart
class AuthLogger {
  static const _category = 'AUTH';
  final AppLogger _logger;

  AuthLogger({AppLogger? logger}) : _logger = logger ?? AppLogger.instance;

  /// Log login attempt - NEVER log passwords or tokens
  void logLoginAttempt({
    required String method, // 'email', 'google', 'apple', etc.
    String? email,
  }) {
    _logger.info(_category, 'Login attempt via $method', metadata: {
      'method': method,
      if (email != null) 'email': SensitiveDataRedactor.redactEmail(email),
    });
  }

  void logLoginSuccess({
    required String method,
    required String userId,
    String? email,
  }) {
    _logger.info(_category, 'Login successful via $method', metadata: {
      'method': method,
      'userId': userId,
      if (email != null) 'email': SensitiveDataRedactor.redactEmail(email),
    });

    // Set user context for all subsequent logs
    _logger.setGlobalContext('userId', userId);
  }

  void logLoginFailure({
    required String method,
    required String reason,
    String? email,
  }) {
    _logger.warning(_category, 'Login failed via $method: $reason', metadata: {
      'method': method,
      'reason': reason,
      if (email != null) 'email': SensitiveDataRedactor.redactEmail(email),
      // NEVER log the password or token that failed
    });
  }

  void logLogout({String? userId, String? reason}) {
    _logger.info(_category, 'User logged out', metadata: {
      if (userId != null) 'userId': userId,
      if (reason != null) 'reason': reason,
    });
  }

  void logTokenRefresh({required bool success, String? error}) {
    if (success) {
      _logger.debug(_category, 'Token refreshed successfully');
    } else {
      _logger.warning(_category, 'Token refresh failed',
          metadata: {'error': error ?? 'unknown'});
    }
  }

  void logPasswordResetRequest({String? email}) {
    _logger.info(_category, 'Password reset requested', metadata: {
      if (email != null) 'email': SensitiveDataRedactor.redactEmail(email),
    });
  }

  void logRegistration({
    required String method,
    required bool success,
    String? userId,
    String? error,
  }) {
    final level = success ? LogLevel.info : LogLevel.warning;
    _logger._log(level, _category,
        'Registration ${success ? "completed" : "failed"} via $method',
        metadata: {
          'method': method,
          'success': success,
          if (userId != null) 'userId': userId,
          if (error != null) 'error': error,
        });
  }

  void logMfaChallenge({required String type, required bool success}) {
    _logger.info(
        _category, 'MFA $type ${success ? "verified" : "failed"}', metadata: {
      'mfaType': type,
      'success': success,
    });
  }
}

