// lib/logging/performance_logger.dart
class PerformanceLogger {
  static const _category = 'PERFORMANCE';
  final AppLogger _logger;
  final Map<String, Stopwatch> _traces = {};

  PerformanceLogger({AppLogger? logger})
      : _logger = logger ?? AppLogger.instance;

  void startTrace(String name) {
    _traces[name] = Stopwatch()..start();
  }

  void endTrace(String name, {Map<String, dynamic>? metadata}) {
    final stopwatch = _traces.remove(name);
    if (stopwatch == null) return;
    stopwatch.stop();

    final level = stopwatch.elapsedMilliseconds > 3000
        ? LogLevel.warning
        : LogLevel.info;

    _logger._log(level, _category,
        'Trace "$name" completed in ${stopwatch.elapsedMilliseconds}ms',
        metadata: {
          'trace': name,
          'durationMs': stopwatch.elapsedMilliseconds,
          if (metadata != null) ...metadata,
        });
  }

  void logFrameDrop({required int droppedFrames, required Duration duration}) {
    if (droppedFrames > 5) {
      _logger.warning(_category, 'Frame drops detected: $droppedFrames frames',
          metadata: {
            'droppedFrames': droppedFrames,
            'durationMs': duration.inMilliseconds,
          });
    }
  }

  void logMemoryWarning() {
    _logger.warning(_category, 'Memory warning received');
  }
}

