import 'dart:async';
import 'package:flutter/foundation.dart';

class CrashReporter {
  static void initialize() {
    // Catch Flutter framework errors
    FlutterError.onError = (FlutterErrorDetails details) {
      AppLogger.instance.fatal(
        'CRASH',
        'Flutter error: ${details.exceptionAsString()}',
        metadata: {
          'library': details.library ?? 'unknown',
          'context': details.context?.toString(),
        },
        stackTrace: details.stack,
      );

      // Still report to Flutter's default handler in debug mode
      if (kDebugMode) {
        FlutterError.presentError(details);
      }
    };

    // Catch async errors
    PlatformDispatcher.instance.onError = (error, stack) {
      AppLogger.instance.fatal(
        'CRASH',
        'Uncaught async error: $error',
        stackTrace: stack,
      );
      return true;
    };
  }

  static Future<void> runGuarded(Future<void> Function() app) async {
    await runZonedGuarded(
      () async => app(),
      (error, stackTrace) {
        AppLogger.instance.fatal(
          'CRASH',
          'Zoned error: $error',
          stackTrace: stackTrace,
        );
      },
    );
  }
}

// lib/main.dart - Example initialization
import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';

void main() async {
  WidgetsFlutterBinding.ensureInitialized();

  // Configure logging based on build mode
  final sinks = <LogSink>[
    ConsoleLogSink(
      minimumLevel: kDebugMode ? LogLevel.verbose : LogLevel.warning,
    ),
    FileLogSink(
      minimumLevel: kDebugMode ? LogLevel.debug : LogLevel.info,
    ),
  ];

  // Only add remote sink in production
  if (kReleaseMode) {
    sinks.add(RemoteLogSink(
      endpoint: 'https://your-logging-service.example.com/api/logs',
      minimumLevel: LogLevel.warning,
    ));
  }

  AppLogger.initialize(
    sinks: sinks,
    minimumLevel: kDebugMode ? LogLevel.verbose : LogLevel.info,
    globalContext: {
      'appVersion': '1.0.0',
      'buildNumber': '42',
      'platform': defaultTargetPlatform.name,
    },
  );

  CrashReporter.initialize();

  await CrashReporter.runGuarded(() async {
    runApp(const MyApp());
  });
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Production App',
      navigatorObservers: [LoggingNavigatorObserver()],
      home: const HomeScreen(),
    );
  }
}

class HomeScreen extends StatelessWidget {
  const HomeScreen({super.key});

  @override
  Widget build(BuildContext context) {
    return const Scaffold(
      body: Center(child: Text('Secure Logging Demo')),
    );
  }
}

// lib/logging/example_usage.dart
// Demonstrates proper usage patterns

class ExampleAuthService {
  final AuthLogger _authLogger = AuthLogger();
  final LoggingHttpClient _httpClient = LoggingHttpClient();

  Future<void> login(String email, String password) async {
    // ✅ CORRECT: Log the attempt without the password
    _authLogger.logLoginAttempt(method: 'email', email: email);

    // ❌ NEVER DO THIS:
    // logger.info('AUTH', 'Login with password: $password');
    // logger.info('AUTH', 'Token received: $token');

    try {
      // The HTTP client automatically logs request/response with redacted headers
      final response = await _httpClient.post(
        Uri.parse('https://api.example.com/auth/login'),
        headers: {'Content-Type': 'application/json'},
        body: '{"email":"$email","password":"$password"}',
        // The body is NOT logged by our interceptor - only content length
      );

      if (response.statusCode == 200) {
        _authLogger.logLoginSuccess(
          method: 'email',
          userId: 'extracted-user-id',
          email: email,
        );
      } else {
        _authLogger.logLoginFailure(
          method: 'email',
          reason: 'HTTP ${response.statusCode}',
          email: email,
        );
      }
    } catch (e, stack) {
      _authLogger.logLoginFailure(
        method: 'email',
        reason: e.toString(),
        email: email,
      );
    }
  }
}

class ExampleDatabaseService {
  final DatabaseLogger _dbLogger = DatabaseLogger();

  Future<void> getUser(String userId) async {
    final stopwatch = Stopwatch()..start();

    try {
      // ... perform database query ...
      stopwatch.stop();

      _dbLogger.logQuery(
        operation: 'SELECT',
        table: 'users',
        rowsAffected: 1,
        duration: stopwatch.elapsed,
        parameters: {'userId': userId},
        // Parameters are automatically redacted if they contain sensitive keys
      );
    } catch (e, stack) {
      _dbLogger.logError(
        operation: 'SELECT',
        table: 'users',
        error: e,
        stackTrace: stack,
      );
    }
  }
}